"use client";

import { useEffect, useRef } from "react";

import { useGameStore } from "@/store/game-store";

import {
  dispatchGameKey,
  type InputDispatchDeps,
} from "./dispatcher";
import { routePanelKey } from "./panel-focus";

const INPUT_LOCK_MS = 50;

export function GameInputOwner() {
  useGameInputOwner();
  return null;
}

export const useGameInputOwner = (): void => {
  const unlockTimer = useRef<number | null>(null);

  useEffect(() => {
    const unlock = (): void => {
      if (unlockTimer.current !== null) {
        window.clearTimeout(unlockTimer.current);
        unlockTimer.current = null;
      }

      useGameStore.getState().setInputLocked(false);
    };

    const lockInput = (): void => {
      useGameStore.getState().setInputLocked(true);
      if (unlockTimer.current !== null) {
        window.clearTimeout(unlockTimer.current);
      }

      unlockTimer.current = window.setTimeout(unlock, INPUT_LOCK_MS);
    };

    const onKeyDown = (event: KeyboardEvent): void => {
      if (event.defaultPrevented || isEditableTarget(event.target)) {
        return;
      }

      if (routePanelKey({ key: event.key, repeat: event.repeat })) {
        event.preventDefault();
        return;
      }

      const store = useGameStore.getState();
      const deps: InputDispatchDeps = {
        dispatchAction: store.dispatchAction,
        patchUi: store.patchUi,
        appendInputFeedback: store.appendInputFeedback,
        lockInput,
      };
      const result = dispatchGameKey(
        {
          gameState: store.gameState,
          ui: store.ui,
        },
        deps,
        {
          key: event.key,
          repeat: event.repeat,
        },
      );

      if (result.preventDefault) {
        event.preventDefault();
      }
    };

    window.addEventListener("keydown", onKeyDown);

    return () => {
      window.removeEventListener("keydown", onKeyDown);
      unlock();
    };
  }, []);
};

const isEditableTarget = (target: EventTarget | null): boolean => {
  if (!(target instanceof HTMLElement)) {
    return false;
  }

  if (target.isContentEditable) {
    return true;
  }

  const tagName = target.tagName.toLowerCase();

  return tagName === "input" || tagName === "textarea" || tagName === "select";
};

export const isTerminal = (state: GameState): boolean =>
  state.run.terminalStatus !== ACTIVE_TERMINAL_STATUS;

export const createNoopTurnHooks = (): ResolvedTurnHooks => ({
  actorTurn: ({ state }) => state,
  ticks: {
    damageOverTime: ({ state }) => state,
    durations: ({ state }) => state,
    hunger: ({ state }) => state,
    regen: ({ state }) => state,
  },
});

const applyPlayerAction = (
  state: GameState,
  action: PlayerAction,
): ActionResolverResult => {
  if (action.kind === "abort") {
    const status = config.runStructure.terminalStates.abort;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player aborted the run",
        }),
      ],
    };
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= config.runStructure.depthFloors
  ) {
    const status = config.runStructure.terminalStates.win;
    const terminalState = withTerminalStatus(state, status);

    return {
      state: terminalState,
      events: [
        turnEvent(state.run.turn, "terminal_state", {
          status,
          reason: "player descended from the final floor",
        }),
      ],
    };
  }

    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });

